// Currently: no logging implemented

const logEntries = [];

// Helper function to mask email addresses
function maskEmail(email) {
  if (!email || typeof email !== 'string') return null;
  const atIndex = email.indexOf('@');
  if (atIndex <= 0) return null;
  return email[0] + '***' + email.substring(atIndex);
}

// Helper function to determine severity based on event
function getSeverity(eventType, success) {
  if (eventType === 'login_attempt' && success === false) return 'warning';
  if (eventType === 'login_attempt' && success === true) return 'info';
  if (eventType === 'role_change') return 'warning';
  if (eventType === 'data_export') return 'info';
  if (eventType === 'account_lockout') return 'critical';
  return 'info';
}

function logAuthEvent(event) {
  // Extract only the fields we need and are allowed to log
  const logEntry = {
    eventType: event.type || 'login_attempt',
    timestamp: event.timestamp,
    severity: getSeverity(event.type, event.success),
    username: maskEmail(event.username),
    ip: event.ip,
    userAgent: event.userAgent,
    success: event.success
  };

  // Never log passwords or session tokens
  // These fields are explicitly excluded

  logEntries.push(logEntry);
}

function logPermissionChange(event) {
  const logEntry = {
    eventType: event.type || 'role_change',
    timestamp: event.timestamp,
    severity: getSeverity(event.type),
    targetUser: maskEmail(event.targetUser),
    performedBy: maskEmail(event.performedBy),
    oldRole: event.oldRole,
    newRole: event.newRole
  };

  logEntries.push(logEntry);
}

function logDataExport(event) {
  const logEntry = {
    eventType: event.type || 'data_export',
    timestamp: event.timestamp,
    severity: getSeverity(event.type),
    username: maskEmail(event.username),
    exportFormat: event.exportFormat,
    recordCount: event.recordCount
  };

  // Never log patient IDs - they are restricted data
  // Only log the count, not the actual IDs

  logEntries.push(logEntry);
}

function getLogEntries() {
  return [...logEntries];
}

function clearLog() {
  logEntries.length = 0;
}

module.exports = {
  logAuthEvent,
  logPermissionChange,
  logDataExport,
  getLogEntries,
  clearLog,
};
